                categories = []
                for cat in categories_part.split(','):
                    cat = cat.strip()
                    if cat:
                        categories.append(cat)

                # Also split by 'and' if present
                final_categories = []
                for cat in categories:
                    if ' and ' in cat:
                        final_categories.extend([c.strip() for c in cat.split('and') if c.strip()])
                    else:
                        final_categories.append(cat)

                all_categories.extend(final_categories)

    # Clean up duplicates and empty strings
    all_categories = [cat.strip() for cat in all_categories if cat.strip()]

    # Count occurrences
    from collections import Counter
    category_counts = Counter(all_categories)

    output = {
        'status': 'success',
        'total_businesses': len(businesses),
        'category_counts': dict(category_counts.most_common(10))
    }

