all_ratings = rating_list if isinstance(rating_list, list) else []

print('Stats:')
print(f'All businesses: {len(all_businesses)}')
print(f'All ratings: {len(all_ratings)}')

# Identify businesses that accept credit cards
credit_card_businesses = []
for business in all_businesses:
    attrs = business.get('attributes', {})
    if isinstance(attrs, dict) and attrs.get('BusinessAcceptsCreditCards') == 'True':
        credit_card_businesses.append(business)

print(f'Businesses accepting credit cards: {len(credit_card_businesses)}')

# Extract categories from descriptions
from collections import Counter

all_categories = []
for business in credit_card_businesses:
    desc = business.get('description', '')
    if not desc:
        continue

    categories = []

    # Try to extract categories from description
    if 'services in' in desc:
        parts = desc.split('services in')
        if len(parts) > 1:
            categories_part = parts[1]
            # Clean up
            if 'including' in categories_part:
                categories_part = categories_part.split('including')[1]
            if '.' in categories_part:
                categories_part = categories_part.split('.')[0]

            for cat in categories_part.split(','):
                cat = cat.strip()
                if ' and ' in cat:
                    categories.extend([c.strip() for c in cat.split(' and ') if c.strip()])
                elif cat:
                    categories.append(cat)

    elif 'including' in desc:
        parts = desc.split('including')
        if len(parts) > 1:
            categories_part = parts[1]
            if '.' in categories_part:
                categories_part = categories_part.split('.')[0]

            for cat in categories_part.split(','):
                cat = cat.strip()
                if ' and ' in cat:
                    categories.extend([c.strip() for c in cat.split(' and ') if c.strip()])
                elif cat:
                    categories.append(cat)

    all_categories.extend(categories)

# Clean up categories
all_categories = [cat for cat in all_categories if cat and cat != '']

# Count occurrences
category_counts = Counter(all_categories)

print(f'Categories found: {len(category_counts)}')
print(f'Top categories: {category_counts.most_common(10)}')

# Get business IDs for those that accept credit cards
business_ids = [b['business_id'].replace('businessid_', '') for b in credit_card_businesses]

# Get ratings for these businesses
rating_dict = {}
for rating in all_ratings:
    ref_id = rating['business_ref'].replace('businessref_', '')
    rating_dict[ref_id] = float(rating['avg_rating'])

# Match businesses with their ratings
business_with_ratings = []
for business in credit_card_businesses:
    biz_id = business['business_id'].replace('businessid_', '')
    if biz_id in rating_dict:
        business_with_ratings.append({
            'name': business['name'],
            'business_id': business['business_id'],
            'categories': [],  # Will fill from description
            'rating': rating_dict[biz_id]
        })

        # Extract categories for this business
        desc = business.get('description', '')
        categories = []

        if 'services in' in desc:
            parts = desc.split('services in')
            if len(parts) > 1:
                categories_part = parts[1]
                if 'including' in categories_part:
                    categories_part = categories_part.split('including')[1]
                if '.' in categories_part:
                    categories_part = categories_part.split('.')[0]

                for cat in categories_part.split(','):
                    cat = cat.strip()
                    if ' and ' in cat:
                        categories.extend([c.strip() for c in cat.split(' and ') if c.strip()])
                    elif cat:
                        categories.append(cat)

        elif 'including' in desc:
            parts = desc.split('including')
            if len(parts) > 1:
                categories_part = parts[1]
                if '.' in categories_part:
                    categories_part = categories_part.split('.')[0]

                for cat in categories_part.split(','):
                    cat = cat.strip()
                    if ' and ' in cat:
                        categories.extend([c.strip() for c in cat.split(' and ') if c.strip()])
                    elif cat:
                        categories.append(cat)

        business_with_ratings[-1]['categories'] = [cat for cat in categories if cat]

print(f'Businesses with ratings: {len(business_with_ratings)}')

# Calculate average rating by category
category_ratings = {}
for business in business_with_ratings:
    for category in business['categories']:
        if category not in category_ratings:
            category_ratings[category] = {'ratings': [], 'count': 0}
        category_ratings[category]['ratings'].append(business['rating'])
        category_ratings[category]['count'] += 1

# Calculate averages
for category in category_ratings:
    ratings = category_ratings[category]['ratings']
    category_ratings[category]['avg_rating'] = sum(ratings) / len(ratings)

# Sort by count
top_categories = sorted(category_ratings.items(), key=lambda x: x[1]['count'], reverse=True)

print('Top categories by count:')
for cat, data in top_categories[:10]:
    print(f'  {cat}: {data["count"]} businesses, avg rating {data["avg_rating"]:.2f}')

result = {
    'total_credit_card_businesses': len(credit_card_businesses),
    'businesses_with_ratings': len(business_with_ratings),
    'top_category': top_categories[0] if top_categories else None,
    'all_categories': top_categories[:15]
}

print('__RESULT__:')
print(json.dumps(result, default=str))

